import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const t={};function l(p,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p>vant是一个组件库,推荐局部导入</p><p>建议在utils文件夹下创建一个vant的.js文件专门用于导入库组件 再在main.js中导入这个工具类,这样方便管理</p><h3 id="toast" tabindex="-1"><a class="header-anchor" href="#toast"><span>Toast</span></a></h3><p>toast默认是单例的,一旦创建新的toast旧的toast自动销毁, 当使用toast显示加载窗口时指定显示时间为0表示不自动关闭,只能手动关闭 一般在请求拦截器中创建一个toast,在响应拦截器中调用<code>toast.clear()</code>清除加载显示窗口</p><h1 id="postcss" tabindex="-1"><a class="header-anchor" href="#postcss"><span>postcss</span></a></h1><p>postcss是一个插件在vue中默认是px为单位,使用postcss后会在编译时将数值转换为vw的 vw常用于移动端,100vw是一个屏幕的宽度</p><h1 id="打包和发布" tabindex="-1"><a class="header-anchor" href="#打包和发布"><span>打包和发布</span></a></h1><p>目前所做的项目都是基于vue脚手架做的,在真正的网页中识别不了vue,ts,less,sass等高级语法,需要将项目打包编译成网页可识别的htm,css,js的文件 vue脚手架工具已经提供了打包命令,直接使用即可</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm run build</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>会在项目的根目录会自动创建一个文件夹dist，dist中的文件就是打包后的文件，只需要放到服务器中即可。 默认情况下，需要放到服务器根目录打开，如果希望双击运行，需要配置publicPath配成相对路径</p><div class="language-vue.config.js line-numbers-mode" data-highlighter="shiki" data-ext="vue.config.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const { defineConfig } = require(&#39;@vue/cli-service&#39;)</span></span>
<span class="line"><span>module.exports = defineConfig({</span></span>
<span class="line"><span>  publicPath: &#39;./&#39;,</span></span>
<span class="line"><span>  transpileDependencies: true</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="路由懒加载" tabindex="-1"><a class="header-anchor" href="#路由懒加载"><span>路由懒加载</span></a></h3><p>当打包构建应用时，JavaScript包会变得非常大，影响页面加载。如果我们能把不同路由对应的组件分割成不同的代码块，然后当路由被访问的时候才加载对应组件，这样就更加高效了。</p><div class="language-router.js line-numbers-mode" data-highlighter="shiki" data-ext="router.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import Layout from &#39;@/views/layout&#39;</span></span>
<span class="line"><span>import Home from &#39;@/views/layout/home&#39;</span></span>
<span class="line"><span>import Category from &#39;@/views/layout/category&#39;</span></span>
<span class="line"><span>import Cart from &#39;@/views/layout/cart&#39;</span></span>
<span class="line"><span>import User from &#39;@/views/layout/user&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>const Login = () =&gt; import(&#39;@/views/login&#39;)</span></span>
<span class="line"><span>const MyOrder = () =&gt; import(&#39;@/views/myorder&#39;)</span></span>
<span class="line"><span>const Pay = () =&gt; import(&#39;@/views/pay&#39;)</span></span>
<span class="line"><span>const ProDetail = () =&gt; import(&#39;@/views/prodetail&#39;)</span></span>
<span class="line"><span>const Search = () =&gt; import(&#39;@/views/search&#39;)</span></span>
<span class="line"><span>const store = () =&gt; import(&#39;@/store&#39;)</span></span>
<span class="line"><span>const SearchList = () =&gt; import(&#39;@/views/search/list&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>将经常用到的视图打包在一起,不经常用到的视图使用路由懒加载的方式打包</p><h1 id="husky" tabindex="-1"><a class="header-anchor" href="#husky"><span>husky</span></a></h1><p>是在git提交前做代码格式的检查</p><p>安装并初始化</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>pnpm dlx husky-init &amp;&amp; pnpm install</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>初始化时会在当前目录下新建一个<code>.husky</code>文件夹,其中有一个pre-commit文件,这个文件就是提交前要执行的命令</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>pnpm lint</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>lint命令是eslint的命令,它的作用是检查项目所有文件并进行格式化</p><p>使用lint命令当项目体积大时就非常耗时,且有些没有修改的代码也会被无意义地检查,或者拉取的别人的代码和本地格式不一样或并没有husky规范也会出现问题</p><h3 id="暂存区eslint校验" tabindex="-1"><a class="header-anchor" href="#暂存区eslint校验"><span>暂存区eslint校验</span></a></h3><p>在暂存区检查代码</p><p>lint会检查提交的代码和仓库中的代码 lint-staged只会检查暂存区的代码</p><ol><li>安装lint-staged</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>pnpm i lint-staged -D</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>在package.json中配置lint-staged</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&quot;scripts&quot;: {</span></span>
<span class="line"><span>    &quot;lint-staged&quot;: &quot;lint-staged&quot;</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>&quot;lint-staged&quot;: {</span></span>
<span class="line"><span>    &quot;*.{js,ts,vue}&quot;: [</span></span>
<span class="line"><span>      &quot;eslint --fix&quot;</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>.husky/pre-commit文件修改</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>pnpm lint-staged</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="element-plus" tabindex="-1"><a class="header-anchor" href="#element-plus"><span>element-plus</span></a></h1><p>element-plus是一个用于pc端网页开发的组件库 其中AutoImport和Componets插件导入后可以不导入直接使用组件,同时在componets文件夹下的组件也会被自动注册,无需导入即可使用</p>`,34)]))}const r=e(t,[["render",l]]),c=JSON.parse('{"path":"/front/vue/5/","title":"5 第三方工具","lang":"zh-CN","frontmatter":{"title":"5 第三方工具","createTime":"2025/05/05 21:44:20","permalink":"/front/vue/5/"},"readingTime":{"minutes":2.87,"words":860},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/vue/5 第三方工具.md","headers":[]}');export{r as comp,c as data};
